interface Candidate { id: string; embedding: number[]; }
interface ScoredCandidate { id: string; score: number; }

function cosineSimilarity(a: number[], b: number[]): number {
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  if (denom === 0) return 0;
  return dot / denom;
}

function topKNearest(query: number[], candidates: Candidate[], k: number): ScoredCandidate[] {
  const scored = candidates.map(c => ({
    id: c.id,
    score: Math.round(cosineSimilarity(query, c.embedding) * 1000) / 1000
  }));
  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, k);
}
